template <typename T>
T max(T a, T b) {
    return (a > b)? a : b;
}
int main() {
    int a = 10, b = 20;
    cout << max(a, b) << endl; // 使用函数模板处理整型参数
    double x = 3.14, y = 2.71;
    cout << max(x, y) << endl; // 使用函数模板处理浮点型参数
    return 0;
}

template <typename T>
class Stack {
private:
    T* data;
    int top;
    int size;
public:
    Stack(int maxSize) {
        data = new T[maxSize];
        top = -1;
        size = maxSize;
    }
    void push(T item) {
        if (top == size - 1)
            cout << "Stack is full." << endl;
        else
            data++;
    }

T pop() { if(top == -1) { cout << "Stack is empty." << endl; return T(); } else { return data[top--]; } }   
};   
int main() { Stack<int> intStack(5); //使用类模板创建整型栈对象 intStack.push(10); intStack.push(20); cout << intStack.pop() << endl; Stack<double> doubleStack(3); //使用类模板创建浮点型栈对象 doubleStack.push(3.14); doubleStack.push(2.71); cout << doubleStack.pop() << endl; return 0;

